window.LI_SEARCH_INDEX = [{"tipo":"articulo","id":"eco-01","titulo":"Por qué pagamos más cuando el precio termina en ,99€","badge":"Economía conductual","resumen":"El efecto ancla y el precio de imagen izquierda distorsionan la percepción de valor en cada decisión de compra.","texto":"Por qué pagamos más cuando el precio termina en ,99€ Economía conductual El efecto ancla y el precio de imagen izquierda distorsionan la percepción de valor en cada decisión de compra. El precio de 9,99 € no es 10 € menos un céntimo. Es una trampa cognitiva documentada que explota la forma en que tu cerebro procesa los dígitos de izquierda a derecha. El experimento de Thomas y Morwitz El mecanismo psicológico","url":"https://lainferencia.com/articulos/economia/por-que-pagamos-mas-cuando-el-precio-termina-en-99/"},{"tipo":"articulo","id":"eco-02","titulo":"El error que comete tu cerebro al evaluar riesgos financieros","badge":"Toma de decisiones","resumen":"La teoría prospectiva de Kahneman y Tversky demuestra que el dolor de perder dinero es el doble de intenso que el placer de ganarlo.","texto":"El error que comete tu cerebro al evaluar riesgos financieros Toma de decisiones La teoría prospectiva de Kahneman y Tversky demuestra que el dolor de perder dinero es el doble de intenso que el placer de ganarlo. Perder 500 € no duele igual que ganarlos alegra. Duele entre 1,5 y 2,5 veces más. Este asimétrico fundamental explica por qué los inversores venden demasiado pronto las ganancias y aguantan demasiado  El experimento de Kahneman y Tversky El mecanismo psicológico","url":"https://lainferencia.com/articulos/economia/el-error-que-comete-tu-cerebro-al-evaluar-riesgos-financieros/"},{"tipo":"articulo","id":"eco-03","titulo":"Por qué gastas más cuando no ves el dinero físico","badge":"Neuroeconomía","resumen":"El dolor de pagar se atenúa drásticamente con tarjeta o pago digital, lo que dispara el gasto impulsivo de forma sistemática.","texto":"Por qué gastas más cuando no ves el dinero físico Neuroeconomía El dolor de pagar se atenúa drásticamente con tarjeta o pago digital, lo que dispara el gasto impulsivo de forma sistemática. Cuando pagas en efectivo, el cerebro activa la ínsula anterior —la región asociada al dolor físico. Con tarjeta, esa activación desaparece casi por completo. El resultado: gastas más, sin sentirlo. El experimento de Prelec y Simester El mecanismo psicológico","url":"https://lainferencia.com/articulos/economia/por-que-gastas-mas-cuando-no-ves-el-dinero-fisico/"},{"tipo":"articulo","id":"eco-04","titulo":"El efecto IKEA: por qué valoras más lo que construiste tú","badge":"Psicología del consumidor","resumen":"Invertir esfuerzo en algo infla artificialmente su valor percibido, incluso cuando el resultado es objetivamente inferior al de un experto.","texto":"El efecto IKEA: por qué valoras más lo que construiste tú Psicología del consumidor Invertir esfuerzo en algo infla artificialmente su valor percibido, incluso cuando el resultado es objetivamente inferior al de un experto. En 2012, Michael Norton y sus colegas pagaron a participantes para que montaran cajas de IKEA siguiendo las instrucciones. Al terminar, les preguntaron cuánto pagarían por ellas. El resultado fue desc Origami, LEGO y cajas: el esfuerzo como distorsionador del valor El mecanismo: esfuerzo como proxy de valor y extensión del yo","url":"https://lainferencia.com/articulos/economia/el-efecto-ikea-por-que-valoras-mas-lo-que-construiste-tu/"},{"tipo":"articulo","id":"eco-05","titulo":"La paradoja de la elección: por qué más opciones te hacen decidir peor","badge":"Economía conductual","resumen":"Multiplicar las alternativas no mejora las decisiones: las paraliza, aumenta el arrepentimiento y reduce la satisfacción, aunque elijas objetivamente bien.","texto":"La paradoja de la elección: por qué más opciones te hacen decidir peor Economía conductual Multiplicar las alternativas no mejora las decisiones: las paraliza, aumenta el arrepentimiento y reduce la satisfacción, aunque elijas objetivamente bien. En 2000, Sheena Iyengar y Mark Lepper montaron en un supermercado de California dos expositores de mermeladas artesanales: uno con 24 variedades, otro con 6. El de 24 atrajo a más curiosos —era visual La mermelada, el chocolate y el coste oculto de la abundancia Maximizadores y satisficers: dos formas de relacionarse con las opciones","url":"https://lainferencia.com/articulos/economia/la-paradoja-de-la-eleccion-por-que-mas-opciones-te-hacen-decidir/"},{"tipo":"articulo","id":"eco-06","titulo":"El vino de 90€ que costaba 5€: cómo el precio cambia la experiencia real","badge":"Neuroeconomía","resumen":"Cuando los participantes creían beber vino caro, su cerebro lo experimentaba como mejor. El precio no solo cambiaba la opinión: cambiaba la activación neuronal ","texto":"El vino de 90€ que costaba 5€: cómo el precio cambia la experiencia real Neuroeconomía Cuando los participantes creían beber vino caro, su cerebro lo experimentaba como mejor. El precio no solo cambiaba la opinión: cambiaba la activación neuronal real. En 2008, Hilke Plassmann y su equipo del California Institute of Technology pusieron a varios participantes dentro de un escáner de resonancia magnética funcional y los hicieron probar vino. Lo que en El experimento: mismo vino, distinto precio, distinto cerebro El mecanismo: marketing placebo","url":"https://lainferencia.com/articulos/economia/el-vino-de-90-que-costaba-5-como-el-precio-cambia-la-experiencia/"},{"tipo":"articulo","id":"eco-07","titulo":"La música que vendía vino sin que nadie lo supiera","badge":"Psicología del consumidor","resumen":"Cambiar la música de fondo en la sección de vinos triplicó las ventas de la nacionalidad asociada al estilo musical, sin que ningún cliente lo relacionara con l","texto":"La música que vendía vino sin que nadie lo supiera Psicología del consumidor Cambiar la música de fondo en la sección de vinos triplicó las ventas de la nacionalidad asociada al estilo musical, sin que ningún cliente lo relacionara con la música. Durante dos semanas, Adrian North y sus colegas de la Universidad de Leicester pusieron un equipo de música discreto en la sección de vinos de un supermercado del Reino Unido. No cambiaron los precios El experimento: acordeón francés contra brass alemán El mecanismo: priming ambiental","url":"https://lainferencia.com/articulos/economia/la-musica-que-vendia-vino-sin-que-nadie-lo-supiera/"},{"tipo":"articulo","id":"mod-01","titulo":"La ropa que llevas decide cómo piensas: el efecto de la cognición investida","badge":"Cognición vestida","resumen":"Ponerse una bata de médico o un traje formal no cambia solo cómo te ven los demás: cambia mediblemente cómo rinde tu cerebro.","texto":"La ropa que llevas decide cómo piensas: el efecto de la cognición investida Cognición vestida Ponerse una bata de médico o un traje formal no cambia solo cómo te ven los demás: cambia mediblemente cómo rinde tu cerebro. En 2012, Hajo Adam y Adam Galinsky demostraron en una serie de experimentos controlados que ponerse una bata blanca de laboratorio —idéntica en todos los casos— mejoraba el rendimiento en tareas de at El experimento de Adam y Galinsky El mecanismo psicológico","url":"https://lainferencia.com/articulos/moda/la-ropa-que-llevas-decide-como-piensas-el-efecto-de-la-cognicion/"},{"tipo":"articulo","id":"mod-02","titulo":"Por qué el lujo visible hace que te fíen menos","badge":"Señalización social","resumen":"Mostrar marcas de lujo en contextos competitivos activa en los observadores señales de alerta sobre fiabilidad e integridad.","texto":"Por qué el lujo visible hace que te fíen menos Señalización social Mostrar marcas de lujo en contextos competitivos activa en los observadores señales de alerta sobre fiabilidad e integridad. Las marcas de lujo visibles —logos grandes, accesorios reconocibles— generan en los observadores inferencias automáticas sobre estatus y recursos. Sin embargo, en contextos donde la confianza importa  El experimento de Nelissen y Meijers El mecanismo psicológico","url":"https://lainferencia.com/articulos/moda/por-que-el-lujo-visible-hace-que-te-fien-menos/"},{"tipo":"articulo","id":"mod-03","titulo":"El color de tu ropa altera cómo procesan tu mensaje los demás","badge":"Psicología del color","resumen":"Los colores activan esquemas cognitivos automáticos que modulan la credibilidad, la agresividad percibida y la atracción interpersonal.","texto":"El color de tu ropa altera cómo procesan tu mensaje los demás Psicología del color Los colores activan esquemas cognitivos automáticos que modulan la credibilidad, la agresividad percibida y la atracción interpersonal. El rojo no es solo un color. En una serie de seis experimentos, Elliot y Niesta demostraron que las mujeres vestidas de rojo eran valoradas consistentemente como más atractivas por los hombres —y que  El experimento de Elliot y Niesta El mecanismo psicológico","url":"https://lainferencia.com/articulos/moda/el-color-de-tu-ropa-altera-como-procesan-tu-mensaje-los-demas/"},{"tipo":"articulo","id":"mod-04","titulo":"El efecto Diderot: por qué comprar una cosa te hace querer cambiarlo todo","badge":"Psicología del consumo","resumen":"Adquirir un objeto nuevo genera una presión psicológica en cadena para actualizar todo lo que lo rodea, convirtiendo una compra en un ciclo de consumo difícil d","texto":"El efecto Diderot: por qué comprar una cosa te hace querer cambiarlo todo Psicología del consumo Adquirir un objeto nuevo genera una presión psicológica en cadena para actualizar todo lo que lo rodea, convirtiendo una compra en un ciclo de consumo difícil de detener. En 1769, el filósofo Denis Diderot recibió como regalo una suntuosa bata de seda escarlata. Poco después, escribió un ensayo titulado \"Arrepentimiento por mi vieja bata de casa\". El problema: la nueva El mecanismo: coherencia simbólica y presión de identidad Por qué los marketers lo conocen y nosotros no","url":"https://lainferencia.com/articulos/moda/el-efecto-diderot-por-que-comprar-una-cosa-te-hace-querer/"},{"tipo":"articulo","id":"mod-05","titulo":"El uniforme de los que deciden mucho: por qué Einstein, Obama y Zuckerberg visten siempre lo mismo","badge":"Autorregulación cognitiva","resumen":"Eliminar las decisiones triviales del día preserva la capacidad cognitiva para las que realmente importan. La ropa es el laboratorio más visible de este princip","texto":"El uniforme de los que deciden mucho: por qué Einstein, Obama y Zuckerberg visten siempre lo mismo Autorregulación cognitiva Eliminar las decisiones triviales del día preserva la capacidad cognitiva para las que realmente importan. La ropa es el laboratorio más visible de este principio. Barack Obama tomaba miles de decisiones al día como presidente. Por eso tomó una menos: dejó de decidir qué ponerse. \"Solo visto trajes grises o azules —explicó en 2012—. Intento reducir las decisione La fatiga de decisión: el recurso que se agota con cada elección El uniforme como estrategia, no como pereza","url":"https://lainferencia.com/articulos/moda/el-uniforme-de-los-que-deciden-mucho-por-que-einstein-obama-y/"},{"tipo":"articulo","id":"der-01","titulo":"Por qué la memoria de los testigos oculares es la prueba más peligrosa del sistema judicial","badge":"Psicología Forense","resumen":"Más del 70% de las condenas erróneas en EE.UU. demostradas por prueba de ADN incluyeron testimonio ocular como prueba principal.","texto":"Por qué la memoria de los testigos oculares es la prueba más peligrosa del sistema judicial Psicología Forense Más del 70% de las condenas erróneas en EE.UU. demostradas por prueba de ADN incluyeron testimonio ocular como prueba principal. El Innocence Project ha documentado más de 375 condenas erróneas revertidas por prueba de ADN en Estados Unidos desde 1989. En más del 69% de esos casos, el testimonio ocular fue la prueba principal.  El experimento de Loftus: plantar un recuerdo falso en adultos sanos El mecanismo psicológico","url":"https://lainferencia.com/articulos/derecho/por-que-la-memoria-de-los-testigos-oculares-es-la-prueba-mas/"},{"tipo":"articulo","id":"der-02","titulo":"El efecto del lenguaje en los veredictos: cómo las palabras del fiscal deciden la pena","badge":"Lingüística forense","resumen":"La formulación lingüística de los hechos —no solo su contenido— altera sistemáticamente las sentencias que los jurados consideran apropiadas.","texto":"El efecto del lenguaje en los veredictos: cómo las palabras del fiscal deciden la pena Lingüística forense La formulación lingüística de los hechos —no solo su contenido— altera sistemáticamente las sentencias que los jurados consideran apropiadas. Cuando los participantes de un experimento veían el mismo vídeo de un accidente de coche pero se les preguntaba con el verbo \"chocaron\" en lugar de \"se tocaron\", estimaban velocidades más altas, recor El experimento de Loftus y Palmer El mecanismo psicológico","url":"https://lainferencia.com/articulos/derecho/el-efecto-del-lenguaje-en-los-veredictos-como-las-palabras-del/"},{"tipo":"articulo","id":"der-03","titulo":"El juez hambriento: cómo el estado físico decide el veredicto","badge":"Psicología forense","resumen":"Un análisis de 1.112 resoluciones judiciales reveló que los jueces concedían libertad condicional en el 65% de los casos tras comer, y en casi el 0% justo antes","texto":"El juez hambriento: cómo el estado físico decide el veredicto Psicología forense Un análisis de 1.112 resoluciones judiciales reveló que los jueces concedían libertad condicional en el 65% de los casos tras comer, y en casi el 0% justo antes del descanso. Durante diez meses, Shai Danziger y sus colegas siguieron a ocho jueces israelíes que celebraban juntas de libertad condicional para presos. Analizaron 1.112 resoluciones y buscaron el factor que mejo Los datos: un patrón que no debería existir El mecanismo: fatiga cognitiva y default conservador","url":"https://lainferencia.com/articulos/derecho/el-juez-hambriento-como-el-estado-fisico-decide-el-veredicto/"},{"tipo":"articulo","id":"der-04","titulo":"La confesión falsa: por qué personas inocentes confiesan crímenes que no cometieron","badge":"Psicología del interrogatorio","resumen":"Las técnicas de interrogatorio psicológico pueden llevar a personas completamente inocentes a confesar crímenes inventados, y esas confesiones convencen después","texto":"La confesión falsa: por qué personas inocentes confiesan crímenes que no cometieron Psicología del interrogatorio Las técnicas de interrogatorio psicológico pueden llevar a personas completamente inocentes a confesar crímenes inventados, y esas confesiones convencen después a los jurados. El Innocence Project ha documentado más de 375 condenas erróneas revertidas por ADN en Estados Unidos. En el 29% de esos casos, el condenado había firmado una confesión. No porque mintiera estratégica El experimento: colapsar en 60 segundos La técnica Reid y la psicología de la capitulación","url":"https://lainferencia.com/articulos/derecho/la-confesion-falsa-por-que-personas-inocentes-confiesan-crimenes/"},{"tipo":"articulo","id":"dep-01","titulo":"El ritual antes de tirar el penalti que aumenta la precisión un 17%","badge":"Psicología del deporte","resumen":"Los rituales pre-rendimiento no son superstición: reducen la ansiedad cognitiva y estabilizan el control motor en situaciones de alta presión.","texto":"El ritual antes de tirar el penalti que aumenta la precisión un 17% Psicología del deporte Los rituales pre-rendimiento no son superstición: reducen la ansiedad cognitiva y estabilizan el control motor en situaciones de alta presión. En 2010, Lysann Damisch y sus colegas de la Universidad de Colonia demostraron en una serie de experimentos que activar la superstición de un participante —diciéndole \"buena suerte\" o devolviéndole su El experimento de la bola de la suerte El mecanismo psicológico","url":"https://lainferencia.com/articulos/deporte/el-ritual-antes-de-tirar-el-penalti-que-aumenta-la-precision-un/"},{"tipo":"articulo","id":"dep-02","titulo":"Por qué los atletas de élite cometen más errores cuando piensan demasiado","badge":"Neurociencia del rendimiento","resumen":"El fenómeno \"choke under pressure\" ocurre cuando el pensamiento consciente interfiere con patrones motores automatizados que funcionan mejor sin supervisión.","texto":"Por qué los atletas de élite cometen más errores cuando piensan demasiado Neurociencia del rendimiento El fenómeno \"choke under pressure\" ocurre cuando el pensamiento consciente interfiere con patrones motores automatizados que funcionan mejor sin supervisión. Los golfistas expertos cometen más errores cuando se les pide que piensen conscientemente en su swing. Los novatos, en cambio, mejoran con exactamente las mismas instrucciones. La pericia crea automat El experimento de Beilock y Carr El mecanismo psicológico","url":"https://lainferencia.com/articulos/deporte/por-que-los-atletas-de-elite-cometen-mas-errores-cuando-piensan/"},{"tipo":"articulo","id":"dep-03","titulo":"El poder del diálogo interno: cómo la voz en tu cabeza decide el rendimiento","badge":"Psicología del rendimiento","resumen":"El lenguaje que usas contigo mismo durante un esfuerzo —específico, técnico o motivacional según el momento— mejora el rendimiento de forma objetivamente medibl","texto":"El poder del diálogo interno: cómo la voz en tu cabeza decide el rendimiento Psicología del rendimiento El lenguaje que usas contigo mismo durante un esfuerzo —específico, técnico o motivacional según el momento— mejora el rendimiento de forma objetivamente medible. En 2011, Antonis Hatzigeorgiadis y su equipo publicaron un metaanálisis de 32 estudios controlados sobre self-talk —el diálogo interno durante el rendimiento deportivo— que acumulaba datos de más de 6 Instruccional vs. motivacional: dos funciones distintas para dos situaciones distintas El mecanismo: atención, esquemas y autoeficacia","url":"https://lainferencia.com/articulos/deporte/el-poder-del-dialogo-interno-como-la-voz-en-tu-cabeza-decide-el/"},{"tipo":"articulo","id":"dep-04","titulo":"La visualización mental: el entrenamiento que ocurre solo en tu cabeza","badge":"Neurociencia del rendimiento","resumen":"Ensayar mentalmente un movimiento activa los mismos circuitos neurales que ejecutarlo físicamente. Un metaanálisis cuantifica en qué porcentaje mejora el rendim","texto":"La visualización mental: el entrenamiento que ocurre solo en tu cabeza Neurociencia del rendimiento Ensayar mentalmente un movimiento activa los mismos circuitos neurales que ejecutarlo físicamente. Un metaanálisis cuantifica en qué porcentaje mejora el rendimiento sin tocar nada. Los pianistas que practican mentalmente —sin tocar el teclado— activan las mismas regiones motoras que los que practican físicamente. Los cirujanos que visualizan un procedimiento antes de operar come El metaanálisis: números que sorprenden El mecanismo: la realidad funcional de lo imaginado","url":"https://lainferencia.com/articulos/deporte/la-visualizacion-mental-el-entrenamiento-que-ocurre-solo-en-tu/"},{"tipo":"articulo","id":"art-01","titulo":"La psicología detrás de por qué algunas obras de arte te generan euforia física","badge":"Neuroestética","resumen":"El síndrome de Stendhal no es metáfora: la exposición a arte de alta densidad emocional activa los mismos circuitos de recompensa que el orgasmo o la música.","texto":"La psicología detrás de por qué algunas obras de arte te generan euforia física Neuroestética El síndrome de Stendhal no es metáfora: la exposición a arte de alta densidad emocional activa los mismos circuitos de recompensa que el orgasmo o la música. El escalofrío físico ante una obra de arte —o ante el momento cumbre de una pieza musical— tiene un nombre técnico: frisson. Y en 2011, Valorie Salimpoor demostró mediante PET y fMRI que ese escalofrí El experimento de Salimpoor El mecanismo psicológico","url":"https://lainferencia.com/articulos/arte/la-psicologia-detras-de-por-que-algunas-obras-de-arte-te-generan/"},{"tipo":"articulo","id":"art-02","titulo":"Por qué el arte ambiguo activa más el cerebro que el arte figurativo","badge":"Neuroestética","resumen":"La incertidumbre visual fuerza al cerebro a generar múltiples hipótesis simultáneas, lo que maximiza la activación de redes neurales y la experiencia estética.","texto":"Por qué el arte ambiguo activa más el cerebro que el arte figurativo Neuroestética La incertidumbre visual fuerza al cerebro a generar múltiples hipótesis simultáneas, lo que maximiza la activación de redes neurales y la experiencia estética. Las obras que no se dejan descifrar fácilmente generan mayor activación cerebral que las que se entienden al instante. El cerebro, ante la ambigüedad, no se rinde: multiplica sus hipótesis interpretat El experimento de Vessel, Starr y Rubin El mecanismo psicológico","url":"https://lainferencia.com/articulos/arte/por-que-el-arte-ambiguo-activa-mas-el-cerebro-que-el-arte/"},{"tipo":"articulo","id":"art-03","titulo":"La regla pico-final: por qué el último acorde importa más que toda la sinfonía","badge":"Psicología de la experiencia","resumen":"Tu cerebro no evalúa una experiencia por su promedio: la juzga por su momento de mayor intensidad y por cómo termina. La duración, sorprendentemente, importa mu","texto":"La regla pico-final: por qué el último acorde importa más que toda la sinfonía Psicología de la experiencia Tu cerebro no evalúa una experiencia por su promedio: la juzga por su momento de mayor intensidad y por cómo termina. La duración, sorprendentemente, importa muy poco. En 1993, Kahneman y sus colegas realizaron un experimento que debería obligar a replantear cómo diseñamos cualquier experiencia: los conciertos, las presentaciones, los viajes, las reuniones. Pidieron El yo recordador y el yo experiencial: dos sistemas en conflicto La neglect de duración y el diseño de lo memorable","url":"https://lainferencia.com/articulos/arte/la-regla-pico-final-por-que-el-ultimo-acorde-importa-mas-que/"},{"tipo":"articulo","id":"art-04","titulo":"La paradoja de la autenticidad: por qué un Picasso falso e idéntico vale cero","badge":"Psicología del arte y la autenticidad","resumen":"Cuando sabemos que algo es una falsificación perfecta, lo valoramos y sentimos de forma radicalmente diferente aunque sea indistinguible del original. El origen","texto":"La paradoja de la autenticidad: por qué un Picasso falso e idéntico vale cero Psicología del arte y la autenticidad Cuando sabemos que algo es una falsificación perfecta, lo valoramos y sentimos de forma radicalmente diferente aunque sea indistinguible del original. El origen importa más que la experiencia. Imagina que tienes delante dos cuadros absolutamente indistinguibles: pigmentos idénticos, técnica idéntica, dimensiones idénticas. Uno es un Picasso original. El otro es una falsificación perfecta re El esencialismo psicológico: la historia como parte del objeto Cómo el origen cambia la experiencia sensorial real","url":"https://lainferencia.com/articulos/arte/la-paradoja-de-la-autenticidad-por-que-un-picasso-falso-e/"},{"tipo":"articulo","id":"tec-01","titulo":"Por qué el scroll infinito está diseñado para secuestrar tu dopamina","badge":"Psicología del diseño","resumen":"El diseño de refuerzo variable en redes sociales replica el mismo mecanismo neurológico de las máquinas tragaperras para maximizar el tiempo de uso.","texto":"Por qué el scroll infinito está diseñado para secuestrar tu dopamina Psicología del diseño El diseño de refuerzo variable en redes sociales replica el mismo mecanismo neurológico de las máquinas tragaperras para maximizar el tiempo de uso. El feed de Instagram no tiene fondo. El de TikTok tampoco. Eso no es un accidente técnico: es una decisión de diseño deliberada basada en la psicología del refuerzo variable de B.F. Skinner. La incert El experimento de Skinner aplicado al diseño digital El mecanismo psicológico","url":"https://lainferencia.com/articulos/tecnologia/por-que-el-scroll-infinito-esta-disenado-para-secuestrar-tu/"},{"tipo":"articulo","id":"tec-02","titulo":"Cómo las notificaciones fragmentan tu concentración durante 23 minutos por interrupción","badge":"Cognición y tecnología","resumen":"Una sola notificación, aunque no se atienda, rompe el estado de flujo cognitivo y requiere una media de 23 minutos para recuperarlo completamente.","texto":"Cómo las notificaciones fragmentan tu concentración durante 23 minutos por interrupción Cognición y tecnología Una sola notificación, aunque no se atienda, rompe el estado de flujo cognitivo y requiere una media de 23 minutos para recuperarlo completamente. Gloria Mark y su equipo de la Universidad de California Irvine cronometraron durante años el comportamiento real de trabajadores de oficina. Su hallazgo más citado: después de una interrupción, el tra El experimento de Gloria Mark El mecanismo psicológico","url":"https://lainferencia.com/articulos/tecnologia/como-las-notificaciones-fragmentan-tu-concentracion-durante-23/"},{"tipo":"articulo","id":"tec-03","titulo":"El efecto de desinhibición online: por qué la gente dice en internet lo que nunca diría en persona","badge":"Psicología digital","resumen":"La pantalla elimina las señales sociales que regulan el comportamiento en persona, produciendo conductas más extremas en ambos sentidos: más apertura y más agre","texto":"El efecto de desinhibición online: por qué la gente dice en internet lo que nunca diría en persona Psicología digital La pantalla elimina las señales sociales que regulan el comportamiento en persona, produciendo conductas más extremas en ambos sentidos: más apertura y más agresividad. Internet libera algo en las personas. Algunas comparten sus miedos más profundos con extraños en foros de salud mental con una franqueza que nunca tendrían con su médico en persona. Otras insultan, am Los seis factores que producen la desinhibición La desinhibición benigna y la tóxica: las dos caras del mismo fenómeno","url":"https://lainferencia.com/articulos/tecnologia/el-efecto-de-desinhibicion-online-por-que-la-gente-dice-en/"},{"tipo":"articulo","id":"tec-04","titulo":"La burbuja de filtros: cómo el algoritmo te convence de que el mundo piensa como tú","badge":"Psicología de las redes sociales","resumen":"Los sistemas de recomendación reducen sistemáticamente tu exposición a ideas contrarias, creando una ilusión de consenso que distorsiona la percepción de la rea","texto":"La burbuja de filtros: cómo el algoritmo te convence de que el mundo piensa como tú Psicología de las redes sociales Los sistemas de recomendación reducen sistemáticamente tu exposición a ideas contrarias, creando una ilusión de consenso que distorsiona la percepción de la realidad social. En 2011, Eli Pariser observó algo desconcertante en su feed de Facebook: sus amigos conservadores habían desaparecido. No los había bloqueado. No habían dejado de publicar. Simplemente, el algoritmo h Los datos: cuánto sesga el algoritmo y cuánto nos sesgamos nosotros El efecto sobre la percepción de la realidad social","url":"https://lainferencia.com/articulos/tecnologia/la-burbuja-de-filtros-como-el-algoritmo-te-convence-de-que-el/"},{"tipo":"articulo","id":"rel-01","titulo":"El 69% de los conflictos de pareja no tienen solución — y eso está bien","badge":"Psicología de la pareja","resumen":"Tres décadas de investigación con cientos de parejas revelan que la mayoría de sus conflictos son \"perpetuos\" — enraizados en diferencias de personalidad que nu","texto":"El 69% de los conflictos de pareja no tienen solución — y eso está bien Psicología de la pareja Tres décadas de investigación con cientos de parejas revelan que la mayoría de sus conflictos son \"perpetuos\" — enraizados en diferencias de personalidad que nunca desaparecerán. John Gottman empezó a estudiar parejas en los años 70 con una pregunta aparentemente simple: ¿podemos predecir qué matrimonios durarán? Tras grabar miles de horas de conversación en su \"Love Lab\" de l Problemas solucionables vs. problemas perpetuos: la distinción que lo cambia todo Los cuatro jinetes: los predictores reales del divorcio","url":"https://lainferencia.com/articulos/relaciones/el-69-de-los-conflictos-de-pareja-no-tienen-solucion-y-eso-esta/"},{"tipo":"articulo","id":"rel-02","titulo":"El experimento del puente colgante: cuando confundimos el miedo con la atracción","badge":"Atracción interpersonal","resumen":"Cruzar un puente de altura genera la misma activación fisiológica que la atracción romántica, y el cerebro atribuye ese estado de excitación al estímulo más sal","texto":"El experimento del puente colgante: cuando confundimos el miedo con la atracción Atracción interpersonal Cruzar un puente de altura genera la misma activación fisiológica que la atracción romántica, y el cerebro atribuye ese estado de excitación al estímulo más saliente: una persona atractiva cercana. Vancouver, 1974. Un puente colgante de 70 metros de altura sobre el río Capilano oscila suavemente. Un segundo puente, sólido y a solo tres metros del suelo, cruza el mismo río 100 metros más abajo. D El experimento: miedo que se convierte en deseo El mecanismo: la atribución errónea de la excitación","url":"https://lainferencia.com/articulos/relaciones/el-experimento-del-puente-colgante-cuando-confundimos-el-miedo/"},{"tipo":"articulo","id":"rel-03","titulo":"La teoría triangular del amor: por qué cambia lo que sientes con el tiempo y eso no significa que el amor desaparezca","badge":"Psicología del amor","resumen":"El amor tiene tres componentes independientes —pasión, intimidad y compromiso— que evolucionan a ritmos distintos. Confundirlos produce diagnósticos erróneos so","texto":"La teoría triangular del amor: por qué cambia lo que sientes con el tiempo y eso no significa que el amor desaparezca Psicología del amor El amor tiene tres componentes independientes —pasión, intimidad y compromiso— que evolucionan a ritmos distintos. Confundirlos produce diagnósticos erróneos sobre el estado de una relación. La mayoría de los idiomas tienen una sola palabra para el amor. El griego clásico tenía seis. Robert Sternberg propuso en 1986 que esa insuficiencia lingüística tiene consecuencias psicológicas reales Los tres vértices: pasión, intimidad y compromiso Por qué el tiempo cambia el triángulo y cómo interpretarlo","url":"https://lainferencia.com/articulos/relaciones/la-teoria-triangular-del-amor-por-que-cambia-lo-que-sientes-con/"},{"tipo":"articulo","id":"rel-04","titulo":"Tu estilo de apego decide cómo discutes, cómo pides ayuda y cómo te vas","badge":"Psicología del apego","resumen":"El tipo de vínculo que formaste con tus cuidadores en los primeros años predice con sorprendente precisión los patrones de conflicto, cercanía y ruptura en tus ","texto":"Tu estilo de apego decide cómo discutes, cómo pides ayuda y cómo te vas Psicología del apego El tipo de vínculo que formaste con tus cuidadores en los primeros años predice con sorprendente precisión los patrones de conflicto, cercanía y ruptura en tus relaciones adultas. En 1987, Cindy Hazan y Phillip Shaver publicaron un estudio que cambió la psicología de las relaciones adultas: la forma en que los adultos se relacionan románticamente replica, con asombrosa fidelida El estudio: un cuestionario en el periódico que replicó la teoría de Bowlby El mecanismo: los modelos internos de trabajo","url":"https://lainferencia.com/articulos/relaciones/tu-estilo-de-apego-decide-como-discutes-como-pides-ayuda-y-como/"},{"tipo":"articulo","id":"rel-05","titulo":"La soledad es tan letal como fumar 15 cigarrillos al día","badge":"Psicología de la salud","resumen":"Décadas de investigación epidemiológica demuestran que el aislamiento social y la soledad subjetiva son predictores de mortalidad tan potentes como la obesidad,","texto":"La soledad es tan letal como fumar 15 cigarrillos al día Psicología de la salud Décadas de investigación epidemiológica demuestran que el aislamiento social y la soledad subjetiva son predictores de mortalidad tan potentes como la obesidad, el sedentarismo o el tabaquismo. En 2010, Julianne Holt-Lunstad y sus colegas publicaron un metaanálisis que analizaba los datos de 148 estudios longitudinales, con más de 300.000 participantes seguidos durante una media de 7,5 años. El metaanálisis: 148 estudios y una conclusión perturbadora El mecanismo: cómo la soledad destruye el cuerpo","url":"https://lainferencia.com/articulos/relaciones/la-soledad-es-tan-letal-como-fumar-15-cigarrillos-al-dia/"},{"tipo":"articulo","id":"rel-06","titulo":"Diez segundos con una taza caliente cambiaron el juicio sobre un desconocido","badge":"Cognición encarnada","resumen":"Sostener brevemente un café caliente —frente a uno frío— llevó a los participantes a describir a un extraño como más cálido y generoso. La temperatura física y ","texto":"Diez segundos con una taza caliente cambiaron el juicio sobre un desconocido Cognición encarnada Sostener brevemente un café caliente —frente a uno frío— llevó a los participantes a describir a un extraño como más cálido y generoso. La temperatura física y la \"calidez\" social comparten sustrato neuronal. En 2008, Lawrence Williams y John Bargh de la Universidad de Yale publicaron en Science un experimento que cuestionaba un supuesto básico sobre cómo juzgamos a las personas: que ese juicio se forma pr El experimento: la taza de café y el extraño El mecanismo: temperatura física y temperatura social","url":"https://lainferencia.com/articulos/relaciones/diez-segundos-con-una-taza-caliente-cambiaron-el-juicio-sobre-un/"},{"tipo":"articulo","id":"sm-01","titulo":"El estado de flujo: la ciencia detrás de cuando el tiempo desaparece","badge":"Psicología positiva","resumen":"Existe un punto exacto entre el aburrimiento y la ansiedad donde el rendimiento y el bienestar alcanzan su pico simultáneamente. Csikszentmihalyi lo mapeó con d","texto":"El estado de flujo: la ciencia detrás de cuando el tiempo desaparece Psicología positiva Existe un punto exacto entre el aburrimiento y la ansiedad donde el rendimiento y el bienestar alcanzan su pico simultáneamente. Csikszentmihalyi lo mapeó con décadas de investigación. En los años 70, Mihaly Csikszentmihalyi entrevistó a cientos de personas que realizaban actividades que no les pagaban y que nadie les pedía: escaladores, ajedrecistas, cirujanos operando de forma vol Las condiciones del flujo: el canal entre el aburrimiento y la ansiedad El flujo y el cerebro: qué ocurre neurológicamente","url":"https://lainferencia.com/articulos/salud-mental/el-estado-de-flujo-la-ciencia-detras-de-cuando-el-tiempo/"},{"tipo":"articulo","id":"sm-02","titulo":"La ilusión de control: por qué creer que mandas sobre lo que no controlas te mantiene más sano","badge":"Psicología del control","resumen":"Percibir que tienes control sobre tu entorno —aunque esa percepción sea parcialmente ilusoria— tiene efectos biológicos reales y medibles sobre la salud y la lo","texto":"La ilusión de control: por qué creer que mandas sobre lo que no controlas te mantiene más sano Psicología del control Percibir que tienes control sobre tu entorno —aunque esa percepción sea parcialmente ilusoria— tiene efectos biológicos reales y medibles sobre la salud y la longevidad. En 1976, Ellen Langer y Judith Rodin realizaron un experimento en una residencia de ancianos de Connecticut que cambiaría la gerontología y la psicología de la salud. Dividieron a los residentes en do El experimento: cómo una planta puede extender la vida El mecanismo: control, estrés y biología","url":"https://lainferencia.com/articulos/salud-mental/la-ilusion-de-control-por-que-creer-que-mandas-sobre-lo-que-no/"},{"tipo":"articulo","id":"sm-03","titulo":"El ejercicio como antidepresivo: por qué caminar 30 minutos rivaliza con la medicación","badge":"Neurociencia clínica","resumen":"Un estudio controlado de Duke University demostró que el ejercicio aeróbico produce los mismos efectos sobre la depresión mayor que la medicación, con tasas de ","texto":"El ejercicio como antidepresivo: por qué caminar 30 minutos rivaliza con la medicación Neurociencia clínica Un estudio controlado de Duke University demostró que el ejercicio aeróbico produce los mismos efectos sobre la depresión mayor que la medicación, con tasas de recaída significativamente menores a los 10 meses. En 1999, James Blumenthal y su equipo de Duke publicaron un estudio que desafió la jerarquía terapéutica en el tratamiento de la depresión. Durante 16 semanas, asignaron aleatoriamente a 156 adultos c El seguimiento: donde el ejercicio gana claramente El mecanismo biológico: más que endorfinas","url":"https://lainferencia.com/articulos/salud-mental/el-ejercicio-como-antidepresivo-por-que-caminar-30-minutos/"},{"tipo":"articulo","id":"sm-04","titulo":"El estado de flujo: la ciencia de cuando el tiempo desaparece y el yo también","badge":"Psicología positiva","resumen":"Csikszentmihalyi identificó las condiciones precisas bajo las que el cerebro alcanza su rendimiento y bienestar máximos simultáneamente, y demostró que ese esta","texto":"El estado de flujo: la ciencia de cuando el tiempo desaparece y el yo también Psicología positiva Csikszentmihalyi identificó las condiciones precisas bajo las que el cerebro alcanza su rendimiento y bienestar máximos simultáneamente, y demostró que ese estado puede diseñarse. ¿Por qué un cirujano de fama mundial opera voluntariamente sin cobrar en hospitales de países pobres? ¿Por qué un escalador arriesga su vida en una pared de hielo sin ninguna recompensa externa? Mihal La investigación: el muestreo de experiencias a escala La neurociencia del flujo: hipofrontalidad y sistema de recompensa","url":"https://lainferencia.com/articulos/salud-mental/el-estado-de-flujo-la-ciencia-de-cuando-el-tiempo-desaparece-y/"},{"tipo":"articulo","id":"sm-05","titulo":"La autocompasión no es autoindulgencia: la investigación que desmonta el mito","badge":"Psicología positiva","resumen":"Kristin Neff demostró que tratarse a uno mismo con amabilidad ante el fracaso predice mejor el bienestar, la resiliencia y el rendimiento que la autoestima alta","texto":"La autocompasión no es autoindulgencia: la investigación que desmonta el mito Psicología positiva Kristin Neff demostró que tratarse a uno mismo con amabilidad ante el fracaso predice mejor el bienestar, la resiliencia y el rendimiento que la autoestima alta, y sin sus efectos secundarios. La cultura occidental asocia la autoevaluación negativa con la mejora: si no te exiges duramente, si no te criticas con rigor, si no sientes vergüenza ante el fracaso, no te esforzarás por hacerlo mej Autocompasión vs. autoestima: dos constructos muy distintos El mito de la autoindulgencia: por qué la autocompasión mejora el rendimiento","url":"https://lainferencia.com/articulos/salud-mental/la-autocompasion-no-es-autoindulgencia-la-investigacion-que/"},{"tipo":"articulo","id":"edu-01","titulo":"Cómo las notas destruyen el amor por aprender: la investigación que pone en cuestión la evaluación escolar","badge":"Psicología educativa","resumen":"Un metaanálisis de 128 estudios demuestra que las recompensas externas contingentes al rendimiento reducen sistemáticamente la motivación intrínseca por la acti","texto":"Cómo las notas destruyen el amor por aprender: la investigación que pone en cuestión la evaluación escolar Psicología educativa Un metaanálisis de 128 estudios demuestra que las recompensas externas contingentes al rendimiento reducen sistemáticamente la motivación intrínseca por la actividad recompensada. En los años 70, Edward Deci realizó un experimento que los sistemas educativos de todo el mundo todavía prefieren ignorar. Reclutó a estudiantes universitarios para resolver puzzles interesantes —sin  El metaanálisis: 128 estudios y una conclusión incómoda La distinción crítica: informar vs. controlar","url":"https://lainferencia.com/articulos/educacion/como-las-notas-destruyen-el-amor-por-aprender-la-investigacion/"},{"tipo":"articulo","id":"edu-02","titulo":"Los errores deseables: por qué aprender a duras penas es aprender mejor","badge":"Ciencia del aprendizaje","resumen":"Las condiciones de aprendizaje que lo hacen más lento y más difícil en el corto plazo producen retención y transferencia significativamente superiores a largo p","texto":"Los errores deseables: por qué aprender a duras penas es aprender mejor Ciencia del aprendizaje Las condiciones de aprendizaje que lo hacen más lento y más difícil en el corto plazo producen retención y transferencia significativamente superiores a largo plazo. Robert Bjork lleva décadas documentando una paradoja que contradice la intuición sobre el aprendizaje: las condiciones que hacen que el aprendizaje se sienta más fluido y fácil producen, sistemáticame Las tres dificultades mejor documentadas: espaciado, intercalado y recuperación El problema del feedback inmediato: cuándo ayuda y cuándo destruye","url":"https://lainferencia.com/articulos/educacion/los-errores-deseables-por-que-aprender-a-duras-penas-es-aprender/"},{"tipo":"articulo","id":"edu-03","titulo":"El efecto protégé: enseñar para aprender","badge":"Metacognición","resumen":"Los estudiantes que saben que tendrán que explicar el material a otros aprenden más y mejor que los que estudian para un examen, incluso cuando nunca llegan a e","texto":"El efecto protégé: enseñar para aprender Metacognición Los estudiantes que saben que tendrán que explicar el material a otros aprenden más y mejor que los que estudian para un examen, incluso cuando nunca llegan a enseñar a nadie. En 2014, John Nestojko y sus colegas de Washington University realizaron un experimento sencillo pero con implicaciones profundas. Pidieron a dos grupos de estudiantes que leyeran un pasaje largo sobr El experimento: la expectativa de enseñar cambia cómo se aprende El mecanismo: la organización para transmitir activa el procesamiento profundo","url":"https://lainferencia.com/articulos/educacion/el-efecto-protege-ensenar-para-aprender/"},{"tipo":"articulo","id":"edu-04","titulo":"Mentalidad fija vs. mentalidad de crecimiento: la creencia que decide cuánto aprendes","badge":"Psicología educativa","resumen":"Carol Dweck demostró que la creencia sobre si la inteligencia es fija o maleable —no el CI real— predice el rendimiento académico, la respuesta al fracaso y el ","texto":"Mentalidad fija vs. mentalidad de crecimiento: la creencia que decide cuánto aprendes Psicología educativa Carol Dweck demostró que la creencia sobre si la inteligencia es fija o maleable —no el CI real— predice el rendimiento académico, la respuesta al fracaso y el desarrollo a largo plazo. ¿Por qué dos estudiantes con el mismo CI, el mismo entorno familiar y la misma calidad de enseñanza divergen de forma dramática en su desarrollo académico y profesional? Carol Dweck lleva cuatro décad El estudio longitudinal: dos años que demuestran la divergencia La intervención: cambiar la mentalidad en ocho sesiones","url":"https://lainferencia.com/articulos/educacion/mentalidad-fija-vs-mentalidad-de-crecimiento-la-creencia-que/"},{"tipo":"articulo","id":"edu-05","titulo":"Por qué estudiar un tema hasta dominarlo es peor que mezclar todo a la vez","badge":"Ciencia del aprendizaje","resumen":"El efecto de intercalado demuestra que mezclar distintos tipos de problemas en una misma sesión es más frustrante pero produce una comprensión y retención hasta","texto":"Por qué estudiar un tema hasta dominarlo es peor que mezclar todo a la vez Ciencia del aprendizaje El efecto de intercalado demuestra que mezclar distintos tipos de problemas en una misma sesión es más frustrante pero produce una comprensión y retención hasta tres veces superior al estudio en bloques. Hay una forma de estudiar que se siente productiva pero que produce retención mediocre, y una forma que se siente frustrante pero que produce retención excelente. Doug Rohrer lleva más de una década d El experimento: bloques vs. intercalado en matemáticas El mecanismo: discriminación y selección de estrategia","url":"https://lainferencia.com/articulos/educacion/por-que-estudiar-un-tema-hasta-dominarlo-es-peor-que-mezclar/"},{"tipo":"articulo","id":"edu-06","titulo":"Los estudiantes que recibieron los apuntes en Comic Sans los retuvieron mejor","badge":"Ciencia del aprendizaje","resumen":"Diemand-Yauman, Oppenheimer y Vaughan demostraron que presentar material en fuentes difíciles de leer mejora la retención, tanto en laboratorio como en institut","texto":"Los estudiantes que recibieron los apuntes en Comic Sans los retuvieron mejor Ciencia del aprendizaje Diemand-Yauman, Oppenheimer y Vaughan demostraron que presentar material en fuentes difíciles de leer mejora la retención, tanto en laboratorio como en institutos reales de Ohio. En 2011, un equipo de Princeton publicó en Cognition un hallazgo que contradice la lógica de casi todo el diseño educativo moderno: el material presentado en fuentes difíciles de leer —incluyendo Comi El experimento: del laboratorio al aula El mecanismo: la fricción como señal de procesamiento","url":"https://lainferencia.com/articulos/educacion/los-estudiantes-que-recibieron-los-apuntes-en-comic-sans-los/"},{"tipo":"articulo","id":"tra-01","titulo":"El principio del progreso: el único motivador que realmente importa en el trabajo","badge":"Psicología organizacional","resumen":"Un análisis de 12.000 entradas de diario de trabajadores del conocimiento reveló que el predictor más potente del bienestar y la motivación diarios no era el re","texto":"El principio del progreso: el único motivador que realmente importa en el trabajo Psicología organizacional Un análisis de 12.000 entradas de diario de trabajadores del conocimiento reveló que el predictor más potente del bienestar y la motivación diarios no era el reconocimiento ni los incentivos: era hacer avanzar un trabajo con sentido. Teresa Amabile y Steven Kramer pasaron años recogiendo datos de una manera que pocos investigadores han tenido la paciencia de sostener: pedían a trabajadores del conocimiento de distintas industrias  Los datos: los directivos no saben qué motiva a sus equipos El catalítico del progreso: el papel de los gestores y el entorno","url":"https://lainferencia.com/articulos/trabajo/el-principio-del-progreso-el-unico-motivador-que-realmente/"},{"tipo":"articulo","id":"tra-02","titulo":"El crafting del trabajo: cómo rediseñar tu puesto desde dentro sin que nadie te lo pida","badge":"Psicología del trabajo","resumen":"Las personas que proactivamente remodelan las tareas, relaciones y significado de su trabajo reportan más engagement, más sentido y mejor desempeño — sin cambia","texto":"El crafting del trabajo: cómo rediseñar tu puesto desde dentro sin que nadie te lo pida Psicología del trabajo Las personas que proactivamente remodelan las tareas, relaciones y significado de su trabajo reportan más engagement, más sentido y mejor desempeño — sin cambiar de empresa. Amy Wrzesniewski y Jane Dutton pasaron tiempo en un hospital observando y entrevistando al personal de limpieza. En teoría, este era uno de los roles más delimitados y menos autónomos del hospital: el El job crafting en acción: tres dimensiones de rediseño Por qué el sentido importa más que el cargo","url":"https://lainferencia.com/articulos/trabajo/el-crafting-del-trabajo-como-redisenar-tu-puesto-desde-dentro/"},{"tipo":"articulo","id":"tra-03","titulo":"Las reuniones destruyen el pensamiento: la evidencia sobre fragmentación cognitiva en el trabajo","badge":"Neurociencia organizacional","resumen":"El trabajo creativo y cognitivamente exigente requiere bloques de atención sostenida que la cultura de reuniones y open offices sistemáticamente imposibilita.","texto":"Las reuniones destruyen el pensamiento: la evidencia sobre fragmentación cognitiva en el trabajo Neurociencia organizacional El trabajo creativo y cognitivamente exigente requiere bloques de atención sostenida que la cultura de reuniones y open offices sistemáticamente imposibilita. En 1999, el 20% del tiempo productivo de los trabajadores del conocimiento se consumía en reuniones y solicitudes de colaboración. En 2016, esa cifra había alcanzado el 80%. Rob Cross y sus colegas de Los datos: cuánto tiempo hay disponible para pensar La oficina abierta: el entorno diseñado para la interrupción","url":"https://lainferencia.com/articulos/trabajo/las-reuniones-destruyen-el-pensamiento-la-evidencia-sobre/"},{"tipo":"articulo","id":"tra-04","titulo":"Burnout: la diferencia entre estar cansado y estar quemado — y por qué importa","badge":"Psicología organizacional","resumen":"Christina Maslach identificó las tres dimensiones del burnout y demostró que el problema no es el trabajador que no resiste: es el entorno que no permite que na","texto":"Burnout: la diferencia entre estar cansado y estar quemado — y por qué importa Psicología organizacional Christina Maslach identificó las tres dimensiones del burnout y demostró que el problema no es el trabajador que no resiste: es el entorno que no permite que nadie resista durante demasiado tiempo. El burnout se menciona constantemente pero se entiende poco. No es estrés crónico, ni agotamiento puntual, ni la simple consecuencia de trabajar mucho. Christina Maslach lleva cuarenta años estudiando El MBI y las tres dimensiones: agotamiento, cinismo, ineficacia El error del \"individuo quemado\": burnout como problema sistémico","url":"https://lainferencia.com/articulos/trabajo/burnout-la-diferencia-entre-estar-cansado-y-estar-quemado-y-por/"},{"tipo":"articulo","id":"tra-05","titulo":"Por qué los bonus no funcionan: la teoría de la autodeterminación aplicada al trabajo","badge":"Psicología del trabajo","resumen":"Deci y Ryan demostraron que las recompensas externas contingentes no solo no mejoran el rendimiento en tareas complejas: activamente destruyen la motivación int","texto":"Por qué los bonus no funcionan: la teoría de la autodeterminación aplicada al trabajo Psicología del trabajo Deci y Ryan demostraron que las recompensas externas contingentes no solo no mejoran el rendimiento en tareas complejas: activamente destruyen la motivación intrínseca que ya existía. La gestión empresarial lleva más de un siglo construida sobre un axioma que parece de sentido común: las personas trabajan más si se les paga más. Sin embargo, desde los años 70, la psicología ha acum El experimento fundacional y el metaanálisis de 128 estudios Las necesidades psicológicas básicas y el entorno que las satisface","url":"https://lainferencia.com/articulos/trabajo/por-que-los-bonus-no-funcionan-la-teoria-de-la-autodeterminacion/"},{"tipo":"articulo","id":"tra-06","titulo":"El CV idéntico que recibía un 50% menos de llamadas — solo por el nombre","badge":"Psicología organizacional","resumen":"Casi 5.000 CVs enviados a empleos reales mostraron que los nombres percibidos como afroamericanos recibían un 50% menos de respuestas que nombres anglosajones, ","texto":"El CV idéntico que recibía un 50% menos de llamadas — solo por el nombre Psicología organizacional Casi 5.000 CVs enviados a empleos reales mostraron que los nombres percibidos como afroamericanos recibían un 50% menos de respuestas que nombres anglosajones, con méritos idénticos. En 2001, Marianne Bertrand de la Universidad de Chicago y Sendhil Mullainathan del MIT diseñaron un experimento de una sencillez engañosa: enviarían CVs idénticos a empleos reales anunciados en periód El experimento: 4.870 CVs y un único cambio El mecanismo: el sesgo implícito y sus consecuencias reales","url":"https://lainferencia.com/articulos/trabajo/el-cv-identico-que-recibia-un-50-menos-de-llamadas-solo-por-el/"},{"tipo":"articulo","id":"pol-01","titulo":"Por qué tus emociones votan antes que tú","badge":"Intuicionismo moral","resumen":"Haidt demostró que los juicios morales y políticos no se forman razonando: el cerebro decide por intuición primero, y los argumentos se fabrican después para ju","texto":"Por qué tus emociones votan antes que tú Intuicionismo moral Haidt demostró que los juicios morales y políticos no se forman razonando: el cerebro decide por intuición primero, y los argumentos se fabrican después para justificarlo. En 1999, Jonathan Haidt presentó a cientos de estudiantes universitarios una serie de escenarios diseñados para provocar repulsión moral sin que hubiera daño real. En uno de ellos, dos hermanos adulto El experimento del tabú inocuo y la perplejidad moral El mecanismo: el perro emocional y su cola racional","url":"https://lainferencia.com/articulos/politica/por-que-tus-emociones-votan-antes-que-tu/"},{"tipo":"articulo","id":"pol-02","titulo":"Por qué los argumentos contrarios te convencen menos si ya tienes opinión","badge":"Razonamiento motivado","resumen":"Las personas con mayor conocimiento político son más —no menos— resistentes a la información que contradice sus creencias. La sofisticación amplifica el sesgo, ","texto":"Por qué los argumentos contrarios te convencen menos si ya tienes opinión Razonamiento motivado Las personas con mayor conocimiento político son más —no menos— resistentes a la información que contradice sus creencias. La sofisticación amplifica el sesgo, no lo reduce. Durante décadas, la teoría democrática asumió que el problema de la polarización política se resolvería con más educación: ciudadanos mejor informados tomarían decisiones más racionales y se mostraría El experimento: cómo procesa la información política el cerebro comprometido El mecanismo: el cerebro político como abogado defensor","url":"https://lainferencia.com/articulos/politica/por-que-los-argumentos-contrarios-te-convencen-menos-si-ya/"},{"tipo":"articulo","id":"pol-03","titulo":"La polarización que no es ideológica: por qué nos caemos mal aunque pensemos parecido","badge":"Polarización afectiva","resumen":"Stanford midió 40 años de datos electorales y encontró que la antipatía entre partidos creció mucho más que las diferencias ideológicas reales. La guerra políti","texto":"La polarización que no es ideológica: por qué nos caemos mal aunque pensemos parecido Polarización afectiva Stanford midió 40 años de datos electorales y encontró que la antipatía entre partidos creció mucho más que las diferencias ideológicas reales. La guerra política es más tribal que doctrinal. Si le preguntas a un demócrata típico cuántos republicanos son \"extremistas\", te dirá que alrededor del 70%. Si le preguntas a un republicano lo mismo sobre los demócratas, obtendrás una cifra similar Cuarenta años de termómetro afectivo: los datos de Stanford El mecanismo: cuando el partido se convierte en identidad social","url":"https://lainferencia.com/articulos/politica/la-polarizacion-que-no-es-ideologica-por-que-nos-caemos-mal/"},{"tipo":"articulo","id":"pol-04","titulo":"Tu personalidad predice tu voto mejor que tus argumentos","badge":"Personalidad y política","resumen":"La apertura a la experiencia y la escrupulosidad del modelo de los Cinco Grandes predicen la orientación política de forma robusta, incluso a través de diferent","texto":"Tu personalidad predice tu voto mejor que tus argumentos Personalidad y política La apertura a la experiencia y la escrupulosidad del modelo de los Cinco Grandes predicen la orientación política de forma robusta, incluso a través de diferentes culturas e idiomas. Si entras en el dormitorio de alguien sin saber nada sobre sus opiniones políticas, puedes predecir su orientación ideológica con una precisión significativamente mejor que el azar solo mirando sus es El experimento: qué revela tu habitación sobre tu voto El mecanismo: la ideología como función psicológica","url":"https://lainferencia.com/articulos/politica/tu-personalidad-predice-tu-voto-mejor-que-tus-argumentos/"},{"tipo":"articulo","id":"ali-01","titulo":"Por qué comes casi el doble cuando estás en compañía","badge":"Facilitación social","resumen":"El número de personas en la mesa predice la ingesta calórica mejor que el hambre. Con seis o más comensales, comemos de media un 76 % más que en solitario.","texto":"Por qué comes casi el doble cuando estás en compañía Facilitación social El número de personas en la mesa predice la ingesta calórica mejor que el hambre. Con seis o más comensales, comemos de media un 76 % más que en solitario. Hay una variable que predice cuánto vas a comer en tu próxima comida mejor que tu nivel de hambre, que el tipo de alimento y que la hora del día. Esa variable es cuántas personas se sientan contigo a  El experimento: 365 días de diarios alimentarios en condiciones reales El mecanismo: la duración de la comida y el contagio de normas sociales","url":"https://lainferencia.com/articulos/alimentacion/por-que-comes-casi-el-doble-cuando-estas-en-compania/"},{"tipo":"articulo","id":"ali-02","titulo":"Cómo tus emociones controlan lo que comes aunque creas que no","badge":"Alimentación emocional","resumen":"Las emociones no solo influyen en la cantidad de comida: determinan el tipo de alimento, el ritmo de ingesta y la experiencia de cada bocado, a través de cinco ","texto":"Cómo tus emociones controlan lo que comes aunque creas que no Alimentación emocional Las emociones no solo influyen en la cantidad de comida: determinan el tipo de alimento, el ritmo de ingesta y la experiencia de cada bocado, a través de cinco rutas psicológicas distintas. La relación entre emociones y comida es una de las más discutidas en psicología clínica, pero también una de las más malentendidas. Durante décadas se habló de \"comer emocional\" como si fuera un fenóm Las cinco vías: por qué el miedo reduce el apetito y el aburrimiento lo dispara El ciclo de regulación: por qué funciona a corto plazo y falla a largo","url":"https://lainferencia.com/articulos/alimentacion/como-tus-emociones-controlan-lo-que-comes-aunque-creas-que-no/"},{"tipo":"articulo","id":"ali-03","titulo":"La paradoja de las dietas: por qué prohibirte un alimento dispara el deseo de comerlo","badge":"Restricción cognitiva","resumen":"Cuando los dieters violan su restricción, comen más que los no-dieters. La restricción cognitiva no gestiona el hambre: la amplifica y la vuelve incontrolable c","texto":"La paradoja de las dietas: por qué prohibirte un alimento dispara el deseo de comerlo Restricción cognitiva Cuando los dieters violan su restricción, comen más que los no-dieters. La restricción cognitiva no gestiona el hambre: la amplifica y la vuelve incontrolable cuando falla. En 1975, C. Peter Herman y Deborah Mack realizaron en la Universidad de Toronto un experimento que contradijo una de las intuiciones más arraigadas sobre las dietas. Invitaron a mujeres de peso normal El experimento del batido que desbloqueó el hambre El mecanismo: restricción cognitiva frente a regulación fisiológica","url":"https://lainferencia.com/articulos/alimentacion/la-paradoja-de-las-dietas-por-que-prohibirte-un-alimento-dispara/"},{"tipo":"articulo","id":"ali-04","titulo":"El tamaño del plato decide cuánto comes, no el hambre","badge":"Señales de porción","resumen":"Cuando las raciones se duplican, la ingesta calórica aumenta un 30 % sin que los participantes lo noten. El cerebro usa el plato como señal de saciedad; el estó","texto":"El tamaño del plato decide cuánto comes, no el hambre Señales de porción Cuando las raciones se duplican, la ingesta calórica aumenta un 30 % sin que los participantes lo noten. El cerebro usa el plato como señal de saciedad; el estómago llega demasiado tarde. En un experimento de Penn State, cincuenta y un adultos —la mitad con peso normal, la mitad con sobrepeso— recibieron pasta en cuatro tamaños de ración distintos a lo largo de varias semanas. Antes de El experimento: cuatro raciones, un solo resultado El mecanismo: la señal visual como ancla de saciedad","url":"https://lainferencia.com/articulos/alimentacion/el-tamano-del-plato-decide-cuanto-comes-no-el-hambre/"},{"tipo":"escenario","id":"precio-vino","titulo":"El precio que cambia el sabor","badge":"Simulador de Sesgos","resumen":"Dos personas prueban el mismo vino. Solo una cree que es caro. ¿Su cerebro lo experimenta igual?","texto":"El precio que cambia el sabor Antes de probarlo, ya sabes si te va a gustar. Dos personas prueban el mismo vino. Solo una cree que es caro. ¿Su cerebro lo experimenta igual?","url":"https://lainferencia.com/simulador-de-sesgos/el-precio-que-cambia-el-sabor/"},{"tipo":"escenario","id":"perdida-ganancia","titulo":"Ganar o no perder","badge":"Simulador de Sesgos","resumen":"Dos decisiones con el mismo resultado matemático, contadas de forma distinta, no se sienten igual.","texto":"Ganar o no perder La misma decisión, contada de dos formas distintas. Dos decisiones con el mismo resultado matemático, contadas de forma distinta, no se sienten igual.","url":"https://lainferencia.com/simulador-de-sesgos/ganar-o-no-perder/"},{"tipo":"escenario","id":"calidez-social","titulo":"Calidez física, calidez social","badge":"Simulador de Sesgos","resumen":"Sostener algo caliente o frío durante diez segundos, antes de conocer a alguien, cambia lo que piensas de esa persona.","texto":"Calidez física, calidez social Un vaso en la mano puede cambiar cómo juzgas a un desconocido. Sostener algo caliente o frío durante diez segundos, antes de conocer a alguien, cambia lo que piensas de esa persona.","url":"https://lainferencia.com/simulador-de-sesgos/calidez-fisica-calidez-social/"}];
